<?php session_start();include("./LibPdf/fpdf.php");require_once("./classes/mysql.class.php");//largeur page = 190$test = "salut";if(is_numeric($_GET['id_inter']) AND $_GET['id_inter'] > 0){    $db = new MySQL();    $id_inter = (int) $db->SQLfix($_GET['id_inter']);        $db->Query('SELECT id_inter, projet FROM interventions WHERE id_inter="'.$id_inter.'"  AND compte_principal="'.$_SESSION['compte_principal'].'" ');    $row = $db->Row();    if($row->id_inter) //intervention existance    {                $db->Query('SELECT i.id AS id_unique, i.urgente, i.type_location_vente, i.ville, ta.nom AS nom_ta, i.type_location_vente, i.description, i.dpe, i.ges, i.prix, i.id_inter                    FROM interventions AS i                    LEFT JOIN types_affaires AS ta                    ON (i.id_type_affaire = ta.id)                    AND (ta.compte_principal = "'.$_SESSION['compte_principal'].'" )                    WHERE i.id_inter="'.$id_inter.'"                     AND i.compte_principal="'.$_SESSION['compte_principal'].'"                    ');                $row = $db->Row();        $pdf = new FPDF();$pdf->SetAutoPageBreak(true, 0);$pdf->AddPage();$pdf->SetFont('Times','B',65);$pdf->SetTextColor(0,0,0);$pdf->SetFillColor(214, 214, 214);if($row->type_location_vente == 1)    $pdf->Cell(0,35,'LOCATION',0,0,'C',1);else    $pdf->Cell(0,35,'VENTE',0,0,'C',1);if(is_file('./photos_immo/'.$row->id_unique.'.jpg')){    list($width, $height, $type, $attr) = getimagesize('./photos_immo/'.$row->id_unique.'.jpg');     if($width >= $height)    {        $rapport = $width / $height;        $hauteur = round(150 / $rapport);        $pdf->Image('./photos_immo/'.$row->id_unique.'.jpg', 30, round((125-$hauteur)  / 2) + 45, 150, $hauteur);        //55    }    else    {        $rapport = $width / $height;        $largeur = round(115 * $rapport);        $pdf->Image('./photos_immo/'.$row->id_unique.'.jpg', (190-$largeur) / 2 + 10, 50, $largeur, 115);    }}if($row->urgente){    list($width, $height, $type, $attr) = getimagesize('./photos_immo/urgent.gif');     $rapport = $width / $height;    $hauteur = round(60 / $rapport);    $pdf->Image('./photos_immo/urgent.gif', 10, 50, 60, $hauteur);}list($width, $height, $type, $attr) = getimagesize('./photos_immo/dpe.png'); $rapport = $width / $height;$hauteur = round(60 / $rapport);$pdf->Ln(160);$pdf->Image('./photos_immo/dpe/dpe-'.$row->dpe.'.png', 140, 170, 60, $hauteur);$pdf->Image('./photos_immo/ges/ges-'.$row->ges.'.png', 140, 232, 60, $hauteur);$pdf->SetFont('Times','B',15);$pdf->Cell(96,8, utf8_decode($row->nom_ta).' - '.utf8_decode($row->ville), 1, 0, 'L',0);$pdf->SetFont('Times','I',9);$pdf->Cell(29,8, 'Ref Interne : '.$id_inter, 1, 0, 'R',0);$pdf->Ln();$pdf->SetFont('Times','',12);//$pdf->MultiCell(100, 4, "\ntest\ntest\n\n\n\n\n\n\n\n\n\n\n\n", '0');$nb_retour = substr_count($row->description, "\n");$retour = "";$pdf->MultiCell(125, 4, "\n".utf8_decode($row->description), 'LTR');$y = round($pdf->GetY());for($i=$nb_retour; $i< (250 - $y) / 4; $i++)    $retour .= "\n";$pdf->MultiCell(125, 4, $retour, 'LBR');$pdf->SetFont('Times','B',15);if($row->type_location_vente == 1)      $pdf->Cell(125,8, utf8_decode($row->prix).' '.chr(128).' / Mois (HC)', 1, 0, 'R',0);else    $pdf->Cell(125,8, utf8_decode($row->prix).' '.chr(128).' FAI', 1, 0, 'R',0);$pdf->Ln(18);$pdf->SetFont('Times','B',25);$pdf->Cell(125,18, utf8_decode('BLAES-IMMOBILIER'), 'B', 0, 'C',1);$pdf->Ln();$pdf->SetFont('Times','',8);$pdf->Cell(125,5, utf8_decode('Photos et texte non contractuel. Sous réserve d\'erreur typographique'), 0, 0, 'L',1);    $pdf->Output();    }    else        echo 'no intervention';    }?>